

from PIL import Image, ImageDraw
import os

def draw_boxes_denormalized(image_path, data, output_path='marked_image_scaled.jpg'):
    """
    假设数据坐标被归一化到 0-1000，根据图片实际尺寸还原坐标并画框。
    """
    if not os.path.exists(image_path):
        print(f"错误: 找不到图片文件 {image_path}")
        return

    try:
        image = Image.open(image_path)
    except Exception as e:
        print(f"无法打开图片: {e}")
        return

    # 获取图片实际尺寸
    img_width, img_height = image.size
    print(f"图片实际尺寸: {img_width} x {img_height}")

    draw = ImageDraw.Draw(image)
    
    BOX_COLOR = "red"
    BOX_WIDTH = 3
    
    # 假设归一化基数是 1000 (如果效果还不对，可以尝试改为 image.width 或其他基数，但通常是1000)
    NORM_BASE = 1000.0 

    count = 0

    def process_item(item):
        nonlocal count
        source_list = item.get('sourceList', [])
        for source in source_list:
            if source.get('imageId') == '1':
                pixel = source.get('pixel')
                if pixel and isinstance(pixel, list) and len(pixel) == 4:
                    x1, y1, x2, y2 = pixel
                    
                    # === 核心修改：坐标映射 ===
                    # 如果数据确实是归一化的，需要乘上 (实际尺寸 / 1000)
                    # 注意：如果原本数据就是像素坐标，这样做会让框变得巨大或跑偏。
                    # 但根据你的描述，这里进行反归一化处理：
                    
                    real_x1 = int((x1 / NORM_BASE) * img_width)
                    real_y1 = int((y1 / NORM_BASE) * img_height)
                    real_x2 = int((x2 / NORM_BASE) * img_width)
                    real_y2 = int((y2 / NORM_BASE) * img_height)
                    
                    draw.rectangle([real_x1, real_y1, real_x2, real_y2], outline=BOX_COLOR, width=BOX_WIDTH)
                    count += 1

    # 遍历 Head
    head_list = data.get('preDecHead', [])
    for item in head_list:
        process_item(item)

    # 遍历 List
    body_lists = data.get('preDecList', [])
    for row in body_lists:
        for item in row:
            process_item(item)

    print(f"处理完成，共绘制了 {count} 个框 (已按 1000x1000 归一化比例还原)。")
    image.save(output_path)
    print(f"图片已保存至: {output_path}")
    image.show()

